//+------------------------------------------------------------------+
//|                                              SPS_Filter.mqh      |
//|           Session Pressure Score — Filtro de Tendencia Intradía  |
//|                         Versión 1.00 | Jose's Trading Suite       |
//+------------------------------------------------------------------+
//|  CONCEPTO:                                                        |
//|  El SPS mide la presión direccional acumulada de las velas M5    |
//|  previas al rango ORB. Cada vela aporta un "voto" ponderado por  |
//|  su body ratio y su posición temporal (recencia). El resultado   |
//|  es un score normalizado [-1, +1] que indica si el mercado tiene |
//|  presión alcista, bajista, o neutral antes del breakout.         |
//|                                                                   |
//|  PROPIEDADES CLAVE:                                               |
//|  - 100% intradía: solo usa datos del día actual                  |
//|  - No reduce trades cuando el mercado es neutral (coloca ambas) |
//|  - No requiere indicadores externos, APIs ni datos especiales    |
//|  - Funciona en cualquier activo y timeframe                      |
//|  - Reutilizable en cualquier EA futuro via #include              |
//+------------------------------------------------------------------+
#property copyright "Jose's Trading Suite"
#property version   "1.00"

//--------------------------------------------------------------------
//  PARÁMETROS DE ENTRADA DEL FILTRO
//  (Se agregan al grupo de inputs del EA principal)
//--------------------------------------------------------------------
input group "=== FILTRO SPS (Session Pressure Score) ==="
input bool   SPS_Enabled         = true;     // Activar filtro SPS
input int    SPS_LookbackCandles = 12;       // Velas M5 a analizar antes del rango (12 = 1 hora)
input double SPS_Threshold       = 0.25;     // Umbral de señal (0.0–1.0). Más alto = más selectivo
input bool   SPS_UseRecencyBias  = true;     // Ponderar velas más recientes con mayor peso
input bool   SPS_PrintDebug      = false;    // Imprimir SPS en el log (para diagnóstico)

//--------------------------------------------------------------------
//  ENUMERACIÓN DE RESULTADO DEL FILTRO
//--------------------------------------------------------------------
enum ENUM_SPS_SIGNAL
{
   SPS_NEUTRAL   = 0,   // No hay presión clara → colocar BUY y SELL stop
   SPS_BULLISH   = 1,   // Presión alcista detectada → solo BUY stop
   SPS_BEARISH   = -1   // Presión bajista detectada → solo SELL stop
};

//--------------------------------------------------------------------
//  FUNCIÓN PRINCIPAL: Calcular el Session Pressure Score
//
//  Parámetros:
//    symbol          - símbolo del instrumento
//    session_start   - datetime del inicio de la sesión del día
//    range_end       - datetime del fin del rango ORB (momento de análisis)
//    sps_value       - [out] el score raw calculado (-1.0 a +1.0)
//
//  Retorna: ENUM_SPS_SIGNAL (BULLISH / BEARISH / NEUTRAL)
//--------------------------------------------------------------------
ENUM_SPS_SIGNAL SPS_Calculate(
   const string   symbol,
   const datetime session_start,
   const datetime range_end,
   double        &sps_value)
{
   sps_value = 0.0;

   if(!SPS_Enabled)
      return SPS_NEUTRAL;

   // ── Obtener velas M5 en la ventana pre-rango ──────────────────
   // Buscamos hasta SPS_LookbackCandles velas previas al range_end
   // que estén dentro del día actual (>= session_start)

   MqlRates rates[];
   int copied = CopyRates(symbol, PERIOD_M5, range_end,
                          SPS_LookbackCandles + 5, rates);
   if(copied <= 0)
   {
      if(SPS_PrintDebug)
         Print("SPS: No se pudieron obtener velas M5");
      return SPS_NEUTRAL;
   }

   // Filtrar solo velas dentro de la sesión actual
   int    valid_count = 0;
   double sum_score   = 0.0;
   double sum_weights = 0.0;

   // Recorremos de más antiguo a más reciente
   // El índice 0 de CopyRates es el más reciente
   // Necesitamos recorrer en orden inverso para asignar pesos correctos

   int n = ArraySize(rates);
   int candle_idx = 0;  // contador de velas válidas (0 = más reciente)

   for(int i = 0; i < n; i++)
   {
      // Saltear velas fuera de la sesión o posteriores al rango
      if(rates[i].time < session_start) continue;
      if(rates[i].time >= range_end)    continue;

      // Calcular body ratio (qué proporción de la vela es cuerpo real)
      double total_range = rates[i].high - rates[i].low;
      if(total_range < _Point) continue;  // vela plana, ignorar

      double body       = MathAbs(rates[i].close - rates[i].open);
      double body_ratio = body / total_range;   // 0.0 = doji, 1.0 = marubozu

      // Dirección: +1 alcista, -1 bajista
      double direction = (rates[i].close >= rates[i].open) ? 1.0 : -1.0;

      // Peso por recencia (velas más recientes pesan más)
      // candle_idx=0 es la más reciente → peso=SPS_LookbackCandles
      // candle_idx=N-1 es la más antigua → peso=1
      double weight = 1.0;
      if(SPS_UseRecencyBias)
         weight = (double)(SPS_LookbackCandles - candle_idx) /
                  (double)SPS_LookbackCandles;
      weight = MathMax(weight, 0.1);  // mínimo 10% de peso

      sum_score   += direction * body_ratio * weight;
      sum_weights += weight;
      valid_count++;
      candle_idx++;

      if(valid_count >= SPS_LookbackCandles) break;
   }

   if(valid_count == 0 || sum_weights < 0.001)
   {
      if(SPS_PrintDebug)
         Print("SPS: Sin velas válidas en la ventana");
      return SPS_NEUTRAL;
   }

   // Normalizar: score en rango [-1, +1]
   sps_value = sum_score / sum_weights;

   if(SPS_PrintDebug)
      PrintFormat("SPS | Velas=%d  Score=%.4f  Umbral=%.2f",
                  valid_count, sps_value, SPS_Threshold);

   // ── Clasificación ─────────────────────────────────────────────
   if(sps_value >= SPS_Threshold)
      return SPS_BULLISH;
   else if(sps_value <= -SPS_Threshold)
      return SPS_BEARISH;
   else
      return SPS_NEUTRAL;
}

//--------------------------------------------------------------------
//  FUNCIÓN AUXILIAR: Texto descriptivo de la señal SPS
//--------------------------------------------------------------------
string SPS_SignalText(ENUM_SPS_SIGNAL signal, double sps_value)
{
   string intensity = "";
   double abs_val = MathAbs(sps_value);
   if(abs_val >= 0.60)      intensity = "FUERTE";
   else if(abs_val >= 0.40) intensity = "MODERADA";
   else                     intensity = "DÉBIL";

   switch(signal)
   {
      case SPS_BULLISH: return "↑ PRESIÓN ALCISTA " + intensity +
                               StringFormat(" (%.3f)", sps_value);
      case SPS_BEARISH: return "↓ PRESIÓN BAJISTA " + intensity +
                               StringFormat(" (%.3f)", sps_value);
      default:          return "→ NEUTRAL " +
                               StringFormat(" (%.3f)", sps_value);
   }
}
//+------------------------------------------------------------------+

