//+------------------------------------------------------------------+
//|                                      ORB_BreakoutEA_v2.mq5      |
//|               Opening Range Breakout + Session Pressure Score    |
//|                              Jose's Trading Suite - Abril 2026   |
//+------------------------------------------------------------------+
#property copyright   "Jose's Trading Suite"
#property link        ""
#property version     "2.00"
#property description "ORB EA v2 — Session Pressure Score integrado"

#include <Trade\Trade.mqh>

//====================================================================
//  PARÁMETROS DE ENTRADA
//====================================================================

input group "=== CONFIGURACIÓN DEL RANGO ORB ==="
input int     InpRangeCandles    = 3;         // Velas del rango inicial
input int     InpSessionHour     = 9;         // Hora inicio sesión (GMT servidor)
input int     InpSessionMinute   = 0;         // Minutos inicio sesión

input group "=== GESTIÓN DE RIESGO ==="
input double  InpTP_Pips         = 100.0;     // Take Profit (pips)
input double  InpSL_Pips         = 50.0;      // Stop Loss (pips)
input double  InpBE_Pips         = 0.0;       // Breakeven (pips, 0=desactivado)
input double  InpRiskUSD         = 50.0;      // Riesgo en USD por operación
input bool    InpUsePercentRisk  = false;     // Usar % del balance
input double  InpRiskPercent     = 1.0;       // % de riesgo si UsePercent=true

input group "=== DÍAS PERMITIDOS ==="
input bool    InpAllowMonday     = true;      // Lunes
input bool    InpAllowTuesday    = true;      // Martes
input bool    InpAllowWednesday  = true;      // Miércoles
input bool    InpAllowThursday   = false;     // Jueves
input bool    InpAllowFriday     = true;      // Viernes
input bool    InpAllowSaturday   = false;     // Sábado
input bool    InpAllowSunday     = false;     // Domingo

input group "=== FILTRO SPS (Session Pressure Score) ==="
input bool    InpSPS_Enabled         = true;  // Activar filtro SPS
input int     InpSPS_LookbackCandles = 12;    // Velas M5 analizadas antes del rango (12=1h)
input double  InpSPS_Threshold       = 0.25;  // Umbral señal [0.0-1.0]. Mayor = más selectivo
input bool    InpSPS_UseRecencyBias  = true;  // Ponderar velas recientes con mayor peso
input bool    InpSPS_PrintDebug      = false; // Imprimir score SPS en el log

input group "=== CONFIGURACIÓN GENERAL ==="
input bool    InpOnlyOnePerDay   = true;      // Solo un trade por día
input int     InpMagicNumber     = 20260401;  // Magic Number
input string  InpComment         = "ORB_v2";  // Comentario en órdenes

//====================================================================
//  ENUMERACIÓN SPS — definida directamente en el EA
//====================================================================
enum ENUM_SPS_SIGNAL
{
   SPS_NEUTRAL  =  0,   // Sin presión clara → colocar BUY y SELL stop
   SPS_BULLISH  =  1,   // Presión alcista   → solo BUY stop
   SPS_BEARISH  = -1    // Presión bajista   → solo SELL stop
};

//====================================================================
//  VARIABLES GLOBALES
//====================================================================
CTrade   g_Trade;
double   g_PipSize        = 0.0;
int      g_PrevDay        = -1;
bool     g_RangeBuilt     = false;
bool     g_OrdersPlaced   = false;
bool     g_TradeDone      = false;
bool     g_BEApplied      = false;
bool     g_OppCancelled   = false;
double   g_RangeHigh      = 0.0;
double   g_RangeLow       = 0.0;
datetime g_RangeStartTime = 0;
datetime g_RangeEndTime   = 0;
ulong    g_TicketBuy      = 0;
ulong    g_TicketSell     = 0;

ENUM_SPS_SIGNAL g_SPS_Signal = SPS_NEUTRAL;
double          g_SPS_Value  = 0.0;
string          g_SPS_Text   = "Pendiente";

//====================================================================
//  SPS — FUNCIÓN PRINCIPAL
//  Calcula el Session Pressure Score a partir de velas M5
//  anteriores al cierre del rango ORB.
//
//  Retorna: SPS_BULLISH / SPS_BEARISH / SPS_NEUTRAL
//  Escribe el score numérico [-1,+1] en sps_value (parámetro out)
//====================================================================
ENUM_SPS_SIGNAL SPS_Calculate(const string   symbol,
                               const datetime session_start,
                               const datetime range_end,
                               double        &sps_value)
{
   sps_value = 0.0;

   if(!InpSPS_Enabled)
      return SPS_NEUTRAL;

   MqlRates rates[];
   ArraySetAsSeries(rates, true);
   int copied = CopyRates(symbol, PERIOD_M5, range_end,
                          InpSPS_LookbackCandles + 8, rates);
   if(copied <= 0)
   {
      if(InpSPS_PrintDebug)
         Print("SPS: CopyRates devolvió 0 velas");
      return SPS_NEUTRAL;
   }

   int    valid_count = 0;
   double sum_score   = 0.0;
   double sum_weights = 0.0;

   for(int i = 0; i < copied; i++)
   {
      if(rates[i].time >= range_end)    continue;
      if(rates[i].time <  session_start) break;

      double total_range = rates[i].high - rates[i].low;
      if(total_range < _Point)          continue;

      double body       = MathAbs(rates[i].close - rates[i].open);
      double body_ratio = body / total_range;
      double direction  = (rates[i].close >= rates[i].open) ? 1.0 : -1.0;

      // Peso por recencia: vela más reciente (i=0) → peso máximo
      double weight = 1.0;
      if(InpSPS_UseRecencyBias)
      {
         weight = (double)(InpSPS_LookbackCandles - valid_count)
                / (double) InpSPS_LookbackCandles;
         weight = MathMax(weight, 0.1);
      }

      sum_score   += direction * body_ratio * weight;
      sum_weights += weight;
      valid_count++;

      if(valid_count >= InpSPS_LookbackCandles) break;
   }

   if(valid_count == 0 || sum_weights < 0.0001)
   {
      if(InpSPS_PrintDebug)
         Print("SPS: Sin velas válidas en la ventana");
      return SPS_NEUTRAL;
   }

   sps_value = sum_score / sum_weights;

   if(InpSPS_PrintDebug)
      PrintFormat("SPS | Velas=%d  Score=%.4f  Umbral=%.2f",
                  valid_count, sps_value, InpSPS_Threshold);

   if(sps_value >=  InpSPS_Threshold) return SPS_BULLISH;
   if(sps_value <= -InpSPS_Threshold) return SPS_BEARISH;
   return SPS_NEUTRAL;
}

//====================================================================
//  SPS — Texto descriptivo para el panel
//====================================================================
string SPS_SignalText(const ENUM_SPS_SIGNAL signal, const double sps_value)
{
   double av = MathAbs(sps_value);
   string intensity = (av >= 0.60) ? "FUERTE"
                    : (av >= 0.40) ? "MODERADA"
                    :                "DÉBIL";
   switch(signal)
   {
      case SPS_BULLISH:
         return "↑ ALCISTA " + intensity +
                StringFormat(" (%.3f)", sps_value);
      case SPS_BEARISH:
         return "↓ BAJISTA " + intensity +
                StringFormat(" (%.3f)", sps_value);
      default:
         return "↔ NEUTRAL" +
                StringFormat(" (%.3f)", sps_value);
   }
}

//====================================================================
//  OnInit
//====================================================================
int OnInit()
{
   if(InpRangeCandles < 1)
   {
      Alert("InpRangeCandles debe ser >= 1");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(InpSL_Pips <= 0.0 || InpTP_Pips <= 0.0)
   {
      Alert("SL y TP deben ser > 0 pips");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(!InpUsePercentRisk && InpRiskUSD <= 0.0)
   {
      Alert("InpRiskUSD debe ser > 0");
      return INIT_PARAMETERS_INCORRECT;
   }

   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetAsyncMode(false);
   g_Trade.SetTypeFilling(DetectFillingType());
   g_PipSize = _Point * 10.0;

   Print("═══════════════════════════════════════════");
   Print("    ORB BREAKOUT EA v2.00 — Iniciando      ");
   Print("═══════════════════════════════════════════");
   PrintFormat("  Símbolo : %s | TF: M5", _Symbol);
   PrintFormat("  Sesión  : %02d:%02d | Rango: %d velas",
               InpSessionHour, InpSessionMinute, InpRangeCandles);
   PrintFormat("  SL=%.0f | TP=%.0f | BE=%.0f  (pips)",
               InpSL_Pips, InpTP_Pips, InpBE_Pips);
   PrintFormat("  SPS: %s | Lookback=%d | Umbral=%.2f",
               InpSPS_Enabled ? "ON" : "OFF",
               InpSPS_LookbackCandles, InpSPS_Threshold);
   Print("═══════════════════════════════════════════");
   return INIT_SUCCEEDED;
}

//====================================================================
//  OnDeinit
//====================================================================
void OnDeinit(const int reason)
{
   CancelAllPendingOrders();
   Comment("");
   PrintFormat("ORB EA v2 detenido. Razón: %d", reason);
}

//====================================================================
//  OnTick — Lógica principal
//====================================================================
void OnTick()
{
   datetime    now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   // ── Nuevo día: resetear todo ───────────────────────────────
   if(dt.day != g_PrevDay)
   {
      ResetDay(now, (int)dt.day_of_week);
      g_PrevDay = (int)dt.day;
   }

   // ── Filtro de día de semana ────────────────────────────────
   if(!IsDayAllowed((int)dt.day_of_week))
   {
      UpdatePanel("DÍA NO PERMITIDO");
      return;
   }

   // ── Si el día ya terminó ───────────────────────────────────
   if(g_TradeDone)
   {
      UpdatePanel("COMPLETADO");
      return;
   }

   // ── FASE 1: Esperar cierre del rango ──────────────────────
   if(!g_RangeBuilt)
   {
      if(now < g_RangeEndTime)
      {
         UpdatePanel("DEFINIENDO RANGO...");
         return;
      }

      // Rango cerrado: calcular SPS y construir rango
      g_SPS_Signal = SPS_Calculate(_Symbol,
                                    g_RangeStartTime,
                                    g_RangeEndTime,
                                    g_SPS_Value);
      g_SPS_Text = SPS_SignalText(g_SPS_Signal, g_SPS_Value);
      PrintFormat("SPS → %s", g_SPS_Text);

      if(BuildRange())
      {
         g_RangeBuilt = true;
         PrintFormat("Rango ORB | H=%.5f  L=%.5f  Amp=%.5f pts",
                     g_RangeHigh, g_RangeLow,
                     g_RangeHigh - g_RangeLow);
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRange: sin velas válidas. Día omitido.");
         g_TradeDone = true;
         UpdatePanel("SIN RANGO VÁLIDO");
      }
      return;
   }

   // ── FASE 2: Gestión de órdenes activas ────────────────────
   if(g_OrdersPlaced)
      ManageTrade();

   UpdatePanel(GetStatusStr());
}

//====================================================================
//  ResetDay
//====================================================================
void ResetDay(const datetime now, const int dow)
{
   CancelAllPendingOrders();
   g_RangeHigh     = 0.0;
   g_RangeLow      = 0.0;
   g_RangeBuilt    = false;
   g_OrdersPlaced  = false;
   g_TradeDone     = false;
   g_BEApplied     = false;
   g_OppCancelled  = false;
   g_TicketBuy     = 0;
   g_TicketSell    = 0;
   g_SPS_Signal    = SPS_NEUTRAL;
   g_SPS_Value     = 0.0;
   g_SPS_Text      = "Calculando...";

   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight
                        + (datetime)(InpSessionHour  * 3600)
                        + (datetime)(InpSessionMinute * 60);
   g_RangeEndTime       = g_RangeStartTime
                        + (datetime)(InpRangeCandles * PeriodSeconds(PERIOD_M5));

   if(IsDayAllowed(dow))
      PrintFormat("Nuevo día | Sesión: %s → Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
}

//====================================================================
//  BuildRange
//====================================================================
bool BuildRange()
{
   double  hi    = 0.0;
   double  lo    = DBL_MAX;
   int     count = 0;
   int     total = iBars(_Symbol, PERIOD_M5);

   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, PERIOD_M5, i);
      if(t >= g_RangeEndTime)   continue;
      if(t <  g_RangeStartTime) break;

      double barHi = iHigh(_Symbol, PERIOD_M5, i);
      double barLo = iLow (_Symbol, PERIOD_M5, i);
      if(barHi > hi) hi = barHi;
      if(barLo < lo) lo = barLo;
      count++;
   }

   PrintFormat("BuildRange: %d vela(s) procesadas [%s - %s]",
               count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));

   if(count == 0 || hi <= lo || hi == 0.0)
      return false;

   g_RangeHigh = hi;
   g_RangeLow  = lo;
   return true;
}

//====================================================================
//  PlacePendingOrders — con decisión direccional SPS
//====================================================================
void PlacePendingOrders()
{
   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist  = InpSL_Pips  * g_PipSize;
   double tpDist  = InpTP_Pips  * g_PipSize;
   double minDist = (double)SymbolInfoInteger(_Symbol,
                    SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots    = CalculateLotSize();
   bool   placed  = false;

   if(lots <= 0.0)
   {
      Print("PlacePendingOrders: lotaje inválido. Día omitido.");
      g_TradeDone = true;
      return;
   }

   //─── Decisión SPS ────────────────────────────────────────────
   //  NEUTRAL  → ambas órdenes (comportamiento estándar ORB)
   //  BULLISH  → solo BUY STOP
   //  BEARISH  → solo SELL STOP
   bool allowBuy  = (g_SPS_Signal != SPS_BEARISH);
   bool allowSell = (g_SPS_Signal != SPS_BULLISH);

   PrintFormat("Órdenes permitidas: BUY=%s  SELL=%s  [SPS=%s]",
               allowBuy  ? "SI" : "NO",
               allowSell ? "SI" : "NO",
               g_SPS_Text);

   //─── BUY STOP ────────────────────────────────────────────────
   if(allowBuy && g_RangeHigh > ask + minDist)
   {
      double entry = NormalizeDouble(g_RangeHigh, _Digits);
      double sl    = NormalizeDouble(entry - slDist, _Digits);
      double tp    = NormalizeDouble(entry + tpDist, _Digits);

      if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp,
                          ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketBuy = g_Trade.ResultOrder();
         PrintFormat("BUY STOP colocado | #%d  E=%.5f  SL=%.5f  TP=%.5f  L=%.2f",
                     (int)g_TicketBuy, entry, sl, tp, lots);
         placed = true;
      }
      else
         PrintFormat("Error BUY STOP: %s (%d)",
                     g_Trade.ResultRetcodeDescription(),
                     g_Trade.ResultRetcode());
   }

   //─── SELL STOP ───────────────────────────────────────────────
   if(allowSell && g_RangeLow < bid - minDist)
   {
      double entry = NormalizeDouble(g_RangeLow, _Digits);
      double sl    = NormalizeDouble(entry + slDist, _Digits);
      double tp    = NormalizeDouble(entry - tpDist, _Digits);

      if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp,
                           ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketSell = g_Trade.ResultOrder();
         PrintFormat("SELL STOP colocado | #%d  E=%.5f  SL=%.5f  TP=%.5f  L=%.2f",
                     (int)g_TicketSell, entry, sl, tp, lots);
         placed = true;
      }
      else
         PrintFormat("Error SELL STOP: %s (%d)",
                     g_Trade.ResultRetcodeDescription(),
                     g_Trade.ResultRetcode());
   }

   g_OrdersPlaced = placed;
   if(!placed)
   {
      Print("Sin órdenes colocadas. Día terminado.");
      g_TradeDone = true;
   }
}

//====================================================================
//  ManageTrade
//====================================================================
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();

   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      {
         CancelAllPendingOrders();
         g_OppCancelled = true;
         Print("Breakout activado | Orden opuesta cancelada. #",
               (string)posTicket);
      }
      if(!g_BEApplied && InpBE_Pips > 0.0)
         ApplyBreakeven(posTicket);
      return;
   }

   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay)
      {
         g_TradeDone = true;
         Print("Posición cerrada. Día completado (OnlyOnePerDay=ON).");
      }
      else
      {
         Print("Posición cerrada. Re-colocando órdenes...");
         g_OppCancelled = false;
         g_BEApplied    = false;
         g_TicketBuy    = 0;
         g_TicketSell   = 0;
         PlacePendingOrders();
      }
      return;
   }

   bool buyPending  = (g_TicketBuy  > 0 && IsOrderPending(g_TicketBuy));
   bool sellPending = (g_TicketSell > 0 && IsOrderPending(g_TicketSell));
   if(!buyPending && !sellPending)
   {
      g_TradeDone = true;
      Print("Órdenes expiradas sin activación. Día terminado.");
   }
}

//====================================================================
//  ApplyBreakeven
//====================================================================
void ApplyBreakeven(const ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;

   ENUM_POSITION_TYPE posType    = (ENUM_POSITION_TYPE)
                                    PositionGetInteger(POSITION_TYPE);
   double             openPrice  = PositionGetDouble(POSITION_PRICE_OPEN);
   double             currentSL  = PositionGetDouble(POSITION_SL);
   double             currentTP  = PositionGetDouble(POSITION_TP);
   double             beDistance = InpBE_Pips * g_PipSize;
   double             bid        = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double             ask        = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double             newSL      = 0.0;
   bool               doModify   = false;

   if(posType == POSITION_TYPE_BUY)
   {
      if(bid >= openPrice + beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(newSL > currentSL) doModify = true;
      }
   }
   else
   {
      if(ask <= openPrice - beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(currentSL == 0.0 || newSL < currentSL) doModify = true;
      }
   }

   if(doModify)
   {
      if(g_Trade.PositionModify(ticket, newSL, currentTP))
      {
         g_BEApplied = true;
         PrintFormat("BE aplicado | #%d  Nuevo SL=%.5f",
                     (int)ticket, newSL);
      }
      else
         PrintFormat("Error BE: %s (%d)",
                     g_Trade.ResultRetcodeDescription(),
                     g_Trade.ResultRetcode());
   }
}

//====================================================================
//  CalculateLotSize
//====================================================================
double CalculateLotSize()
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk
                     ? (balance * InpRiskPercent / 100.0)
                     : InpRiskUSD;

   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickValue <= 0.0)
   {
      PrintFormat("CalculateLotSize: tick info inválida (tv=%.5f ts=%.5f)",
                  tickValue, tickSize);
      return 0.0;
   }

   double valuePerPip = tickValue * (g_PipSize / tickSize);
   if(valuePerPip <= 0.0) return 0.0;

   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   PrintFormat("Lotaje: %.2f  (Riesgo=$%.2f | $/pip=%.4f | Balance=$%.2f)",
               lots, riskAmount, valuePerPip, balance);
   return lots;
}

//====================================================================
//  Utilidades
//====================================================================
ulong FindOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      ulong t = PositionGetTicket(i);
      if(PositionGetString(POSITION_SYMBOL)  == _Symbol &&
         PositionGetInteger(POSITION_MAGIC)  == (long)InpMagicNumber)
         return t;
   }
   return 0;
}

bool IsOrderPending(const ulong ticket)
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
      if(OrderGetTicket(i) == ticket) return true;
   return false;
}

void CancelAllPendingOrders()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      ulong t = OrderGetTicket(i);
      if(OrderGetInteger(ORDER_MAGIC)  == (long)InpMagicNumber &&
         OrderGetString(ORDER_SYMBOL)  == _Symbol)
      {
         if(g_Trade.OrderDelete(t))
            Print("Orden cancelada: #", (string)t);
         else
            PrintFormat("Error cancelando #%d: %s (%d)",
                        (int)t,
                        g_Trade.ResultRetcodeDescription(),
                        g_Trade.ResultRetcode());
      }
   }
   g_TicketBuy  = 0;
   g_TicketSell = 0;
}

bool IsDayAllowed(const int dow)
{
   switch(dow)
   {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
   }
   return false;
}

ENUM_ORDER_TYPE_FILLING DetectFillingType()
{
   uint filling = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((filling & SYMBOL_FILLING_FOK) != 0) return ORDER_FILLING_FOK;
   if((filling & SYMBOL_FILLING_IOC) != 0) return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
}

string GetStatusStr()
{
   if(g_TradeDone)    return "COMPLETADO";
   if(g_OppCancelled) return "EN POSICIÓN";
   if(g_OrdersPlaced) return "ESPERANDO RUPTURA";
   if(g_RangeBuilt)   return "RANGO DEFINIDO";
   return "DEFINIENDO RANGO";
}

void UpdatePanel(const string status)
{
   string arrow = "↔ NEUTRAL";
   if(g_SPS_Signal == SPS_BULLISH) arrow = "↑ ALCISTA";
   if(g_SPS_Signal == SPS_BEARISH) arrow = "↓ BAJISTA";

   string div = "─────────────────────────────\n";
   string txt =
      "  ORB BREAKOUT EA  v2.00\n"                                         + div +
      "  Símbolo : " + _Symbol + "   TF: M5\n"                            +
      "  Sesión  : " + TimeToString(g_RangeStartTime, TIME_MINUTES) +
      " → " + TimeToString(g_RangeEndTime, TIME_MINUTES) + "\n"           +
      "  H Rango : " + DoubleToString(g_RangeHigh, _Digits) + "\n"        +
      "  L Rango : " + DoubleToString(g_RangeLow,  _Digits) + "\n"        + div +
      "  Estado  : " + status + "\n"                                       +
      "  SPS     : " + arrow  + "\n"                                       +
      "  Score   : " + DoubleToString(g_SPS_Value, 3) +
      "  (±" + DoubleToString(InpSPS_Threshold, 2) + ")\n"                +
      "  BUY  #  : " + (string)g_TicketBuy  + "\n"                        +
      "  SELL #  : " + (string)g_TicketSell + "\n"                        + div;
   Comment(txt);
}
//+------------------------------------------------------------------+
//  FIN DEL EA                                                        |
//+------------------------------------------------------------------+

display_content.json_block:
{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                                      ORB_BreakoutEA_v2.mq5      |
//|               Opening Range Breakout + Session Pressure Score    |
//|                              Jose's Trading Suite - Abril 2026   |
//+------------------------------------------------------------------+
#property copyright   "Jose's Trading Suite"
#property link        ""
#property version     "2.00"
#property description "ORB EA v2 — Session Pressure Score integrado"

#include <Trade\Trade.mqh>

//====================================================================
//  PARÁMETROS DE ENTRADA
//====================================================================

input group "=== CONFIGURACIÓN DEL RANGO ORB ==="
input int     InpRangeCandles    = 3;         // Velas del rango inicial
input int     InpSessionHour     = 9;         // Hora inicio sesión (GMT servidor)
input int     InpSessionMinute   = 0;         // Minutos inicio sesión

input group "=== GESTIÓN DE RIESGO ==="
input double  InpTP_Pips         = 100.0;     // Take Profit (pips)
input double  InpSL_Pips         = 50.0;      // Stop Loss (pips)
input double  InpBE_Pips         = 0.0;       // Breakeven (pips, 0=desactivado)
input double  InpRiskUSD         = 50.0;      // Riesgo en USD por operación
input bool    InpUsePercentRisk  = false;     // Usar % del balance
input double  InpRiskPercent     = 1.0;       // % de riesgo si UsePercent=true

input group "=== DÍAS PERMITIDOS ==="
input bool    InpAllowMonday     = true;      // Lunes
input bool    InpAllowTuesday    = true;      // Martes
input bool    InpAllowWednesday  = true;      // Miércoles
input bool    InpAllowThursday   = false;     // Jueves
input bool    InpAllowFriday     = true;      // Viernes
input bool    InpAllowSaturday   = false;     // Sábado
input bool    InpAllowSunday     = false;     // Domingo

input group "=== FILTRO SPS (Session Pressure Score) ==="
input bool    InpSPS_Enabled         = true;  // Activar filtro SPS
input int     InpSPS_LookbackCandles = 12;    // Velas M5 analizadas antes del rango (12=1h)
input double  InpSPS_Threshold       = 0.25;  // Umbral señal [0.0-1.0]. Mayor = más selectivo
input bool    InpSPS_UseRecencyBias  = true;  // Ponderar velas recientes con mayor peso
input bool    InpSPS_PrintDebug      = false; // Imprimir score SPS en el log

input group "=== CONFIGURACIÓN GENERAL ==="
input bool    InpOnlyOnePerDay   = true;      // Solo un trade por día
input int     InpMagicNumber     = 20260401;  // Magic Number
input string  InpComment         = "ORB_v2";  // Comentario en órdenes

//====================================================================
//  ENUMERACIÓN SPS — definida directamente en el EA
//====================================================================
enum ENUM_SPS_SIGNAL
{
   SPS_NEUTRAL  =  0,   // Sin presión clara → colocar BUY y SELL stop
   SPS_BULLISH  =  1,   // Presión alcista   → solo BUY stop
   SPS_BEARISH  = -1    // Presión bajista   → solo SELL stop
};

//====================================================================
//  VARIABLES GLOBALES
//====================================================================
CTrade   g_Trade;
double   g_PipSize        = 0.0;
int      g_PrevDay        = -1;
bool     g_RangeBuilt     = false;
bool     g_OrdersPlaced   = false;
bool     g_TradeDone      = false;
bool     g_BEApplied      = false;
bool     g_OppCancelled   = false;
double   g_RangeHigh      = 0.0;
double   g_RangeLow       = 0.0;
datetime g_RangeStartTime = 0;
datetime g_RangeEndTime   = 0;
ulong    g_TicketBuy      = 0;
ulong    g_TicketSell     = 0;

ENUM_SPS_SIGNAL g_SPS_Signal = SPS_NEUTRAL;
double          g_SPS_Value  = 0.0;
string          g_SPS_Text   = "Pendiente";

//====================================================================
//  SPS — FUNCIÓN PRINCIPAL
//  Calcula el Session Pressure Score a partir de velas M5
//  anteriores al cierre del rango ORB.
//
//  Retorna: SPS_BULLISH / SPS_BEARISH / SPS_NEUTRAL
//  Escribe el score numérico [-1,+1] en sps_value (parámetro out)
//====================================================================
ENUM_SPS_SIGNAL SPS_Calculate(const string   symbol,
                               const datetime session_start,
                               const datetime range_end,
                               double        &sps_value)
{
   sps_value = 0.0;

   if(!InpSPS_Enabled)
      return SPS_NEUTRAL;

   MqlRates rates[];
   ArraySetAsSeries(rates, true);
   int copied = CopyRates(symbol, PERIOD_M5, range_end,
                          InpSPS_LookbackCandles + 8, rates);
   if(copied <= 0)
   {
      if(InpSPS_PrintDebug)
         Print("SPS: CopyRates devolvió 0 velas");
      return SPS_NEUTRAL;
   }

   int    valid_count = 0;
   double sum_score   = 0.0;
   double sum_weights = 0.0;

   for(int i = 0; i < copied; i++)
   {
      if(rates[i].time >= range_end)    continue;
      if(rates[i].time <  session_start) break;

      double total_range = rates[i].high - rates[i].low;
      if(total_range < _Point)          continue;

      double body       = MathAbs(rates[i].close - rates[i].open);
      double body_ratio = body / total_range;
      double direction  = (rates[i].close >= rates[i].open) ? 1.0 : -1.0;

      // Peso por recencia: vela más reciente (i=0) → peso máximo
      double weight = 1.0;
      if(InpSPS_UseRecencyBias)
      {
         weight = (double)(InpSPS_LookbackCandles - valid_count)
                / (double) InpSPS_LookbackCandles;
         weight = MathMax(weight, 0.1);
      }

      sum_score   += direction * body_ratio * weight;
      sum_weights += weight;
      valid_count++;

      if(valid_count >= InpSPS_LookbackCandles) break;
   }

   if(valid_count == 0 || sum_weights < 0.0001)
   {
      if(InpSPS_PrintDebug)
         Print("SPS: Sin velas válidas en la ventana");
      return SPS_NEUTRAL;
   }

   sps_value = sum_score / sum_weights;

   if(InpSPS_PrintDebug)
      PrintFormat("SPS | Velas=%d  Score=%.4f  Umbral=%.2f",
                  valid_count, sps_value, InpSPS_Threshold);

   if(sps_value >=  InpSPS_Threshold) return SPS_BULLISH;
   if(sps_value <= -InpSPS_Threshold) return SPS_BEARISH;
   return SPS_NEUTRAL;
}

//====================================================================
//  SPS — Texto descriptivo para el panel
//====================================================================
string SPS_SignalText(const ENUM_SPS_SIGNAL signal, const double sps_value)
{
   double av = MathAbs(sps_value);
   string intensity = (av >= 0.60) ? "FUERTE"
                    : (av >= 0.40) ? "MODERADA"
                    :                "DÉBIL";
   switch(signal)
   {
      case SPS_BULLISH:
         return "↑ ALCISTA " + intensity +
                StringFormat(" (%.3f)", sps_value);
      case SPS_BEARISH:
         return "↓ BAJISTA " + intensity +
                StringFormat(" (%.3f)", sps_value);
      default:
         return "↔ NEUTRAL" +
                StringFormat(" (%.3f)", sps_value);
   }
}

//====================================================================
//  OnInit
//====================================================================
int OnInit()
{
   if(InpRangeCandles < 1)
   {
      Alert("InpRangeCandles debe ser >= 1");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(InpSL_Pips <= 0.0 || InpTP_Pips <= 0.0)
   {
      Alert("SL y TP deben ser > 0 pips");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(!InpUsePercentRisk && InpRiskUSD <= 0.0)
   {
      Alert("InpRiskUSD debe ser > 0");
      return INIT_PARAMETERS_INCORRECT;
   }

   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetAsyncMode(false);
   g_Trade.SetTypeFilling(DetectFillingType());
   g_PipSize = _Point * 10.0;

   Print("═══════════════════════════════════════════");
   Print("    ORB BREAKOUT EA v2.00 — Iniciando      ");
   Print("═══════════════════════════════════════════");
   PrintFormat("  Símbolo : %s | TF: M5", _Symbol);
   PrintFormat("  Sesión  : %02d:%02d | Rango: %d velas",
               InpSessionHour, InpSessionMinute, InpRangeCandles);
   PrintFormat("  SL=%.0f | TP=%.0f | BE=%.0f  (pips)",
               InpSL_Pips, InpTP_Pips, InpBE_Pips);
   PrintFormat("  SPS: %s | Lookback=%d | Umbral=%.2f",
               InpSPS_Enabled ? "ON" : "OFF",
               InpSPS_LookbackCandles, InpSPS_Threshold);
   Print("═══════════════════════════════════════════");
   return INIT_SUCCEEDED;
}

//====================================================================
//  OnDeinit
//====================================================================
void OnDeinit(const int reason)
{
   CancelAllPendingOrders();
   Comment("");
   PrintFormat("ORB EA v2 detenido. Razón: %d", reason);
}

//====================================================================
//  OnTick — Lógica principal
//====================================================================
void OnTick()
{
   datetime    now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   // ── Nuevo día: resetear todo ───────────────────────────────
   if(dt.day != g_PrevDay)
   {
      ResetDay(now, (int)dt.day_of_week);
      g_PrevDay = (int)dt.day;
   }

   // ── Filtro de día de semana ────────────────────────────────
   if(!IsDayAllowed((int)dt.day_of_week))
   {
      UpdatePanel("DÍA NO PERMITIDO");
      return;
   }

   // ── Si el día ya terminó ───────────────────────────────────
   if(g_TradeDone)
   {
      UpdatePanel("COMPLETADO");
      return;
   }

   // ── FASE 1: Esperar cierre del rango ──────────────────────
   if(!g_RangeBuilt)
   {
      if(now < g_RangeEndTime)
      {
         UpdatePanel("DEFINIENDO RANGO...");
         return;
      }

      // Rango cerrado: calcular SPS y construir rango
      g_SPS_Signal = SPS_Calculate(_Symbol,
                                    g_RangeStartTime,
                                    g_RangeEndTime,
                                    g_SPS_Value);
      g_SPS_Text = SPS_SignalText(g_SPS_Signal, g_SPS_Value);
      PrintFormat("SPS → %s", g_SPS_Text);

      if(BuildRange())
      {
         g_RangeBuilt = true;
         PrintFormat("Rango ORB | H=%.5f  L=%.5f  Amp=%.5f pts",
                     g_RangeHigh, g_RangeLow,
                     g_RangeHigh - g_RangeLow);
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRange: sin velas válidas. Día omitido.");
         g_TradeDone = true;
         UpdatePanel("SIN RANGO VÁLIDO");
      }
      return;
   }

   // ── FASE 2: Gestión de órdenes activas ────────────────────
   if(g_OrdersPlaced)
      ManageTrade();

   UpdatePanel(GetStatusStr());
}

//====================================================================
//  ResetDay
//====================================================================
void ResetDay(const datetime now, const int dow)
{
   CancelAllPendingOrders();
   g_RangeHigh     = 0.0;
   g_RangeLow      = 0.0;
   g_RangeBuilt    = false;
   g_OrdersPlaced  = false;
   g_TradeDone     = false;
   g_BEApplied     = false;
   g_OppCancelled  = false;
   g_TicketBuy     = 0;
   g_TicketSell    = 0;
   g_SPS_Signal    = SPS_NEUTRAL;
   g_SPS_Value     = 0.0;
   g_SPS_Text      = "Calculando...";

   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight
                        + (datetime)(InpSessionHour  * 3600)
                        + (datetime)(InpSessionMinute * 60);
   g_RangeEndTime       = g_RangeStartTime
                        + (datetime)(InpRangeCandles * PeriodSeconds(PERIOD_M5));

   if(IsDayAllowed(dow))
      PrintFormat("Nuevo día | Sesión: %s → Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
}

//====================================================================
//  BuildRange
//====================================================================
bool BuildRange()
{
   double  hi    = 0.0;
   double  lo    = DBL_MAX;
   int     count = 0;
   int     total = iBars(_Symbol, PERIOD_M5);

   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, PERIOD_M5, i);
      if(t >= g_RangeEndTime)   continue;
      if(t <  g_RangeStartTime) break;

      double barHi = iHigh(_Symbol, PERIOD_M5, i);
      double barLo = iLow (_Symbol, PERIOD_M5, i);
      if(barHi > hi) hi = barHi;
      if(barLo < lo) lo = barLo;
      count++;
   }

   PrintFormat("BuildRange: %d vela(s) procesadas [%s - %s]",
               count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));

   if(count == 0 || hi <= lo || hi == 0.0)
      return false;

   g_RangeHigh = hi;
   g_RangeLow  = lo;
   return true;
}

//====================================================================
//  PlacePendingOrders — con decisión direccional SPS
//====================================================================
void PlacePendingOrders()
{
   double ask     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid     = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist  = InpSL_Pips  * g_PipSize;
   double tpDist  = InpTP_Pips  * g_PipSize;
   double minDist = (double)SymbolInfoInteger(_Symbol,
                    SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots    = CalculateLotSize();
   bool   placed  = false;

   if(lots <= 0.0)
   {
      Print("PlacePendingOrders: lotaje inválido. Día omitido.");
      g_TradeDone = true;
      return;
   }

   //─── Decisión SPS ────────────────────────────────────────────
   //  NEUTRAL  → ambas órdenes (comportamiento estándar ORB)
   //  BULLISH  → solo BUY STOP
   //  BEARISH  → solo SELL STOP
   bool allowBuy  = (g_SPS_Signal != SPS_BEARISH);
   bool allowSell = (g_SPS_Signal != SPS_BULLISH);

   PrintFormat("Órdenes permitidas: BUY=%s  SELL=%s  [SPS=%s]",
               allowBuy  ? "SI" : "NO",
               allowSell ? "SI" : "NO",
               g_SPS_Text);

   //─── BUY STOP ────────────────────────────────────────────────
   if(allowBuy && g_RangeHigh > ask + minDist)
   {
      double entry = NormalizeDouble(g_RangeHigh, _Digits);
      double sl    = NormalizeDouble(entry - slDist, _Digits);
      double tp    = NormalizeDouble(entry + tpDist, _Digits);

      if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp,
                          ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketBuy = g_Trade.ResultOrder();
         PrintFormat("BUY STOP colocado | #%d  E=%.5f  SL=%.5f  TP=%.5f  L=%.2f",
                     (int)g_TicketBuy, entry, sl, tp, lots);
         placed = true;
      }
      else
         PrintFormat("Error BUY STOP: %s (%d)",
                     g_Trade.ResultRetcodeDescription(),
                     g_Trade.ResultRetcode());
   }

   //─── SELL STOP ───────────────────────────────────────────────
   if(allowSell && g_RangeLow < bid - minDist)
   {
      double entry = NormalizeDouble(g_RangeLow, _Digits);
      double sl    = NormalizeDouble(entry + slDist, _Digits);
      double tp    = NormalizeDouble(entry - tpDist, _Digits);

      if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp,
                           ORDER_TIME_GTC, 0, InpComment))
      {
         g_TicketSell = g_Trade.ResultOrder();
         PrintFormat("SELL STOP colocado | #%d  E=%.5f  SL=%.5f  TP=%.5f  L=%.2f",
                     (int)g_TicketSell, entry, sl, tp, lots);
         placed = true;
      }
      else
         PrintFormat("Error SELL STOP: %s (%d)",
                     g_Trade.ResultRetcodeDescription(),
                     g_Trade.ResultRetcode());
   }

   g_OrdersPlaced = placed;
   if(!placed)
   {
      Print("Sin órdenes colocadas. Día terminado.");
      g_TradeDone = true;
   }
}

//====================================================================
//  ManageTrade
//====================================================================
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();

   if(posTicket > 0)
   {
      if(!g_OppCancelled)
      {
         CancelAllPendingOrders();
         g_OppCancelled = true;
         Print("Breakout activado | Orden opuesta cancelada. #",
               (string)posTicket);
      }
      if(!g_BEApplied && InpBE_Pips > 0.0)
         ApplyBreakeven(posTicket);
      return;
   }

   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay)
      {
         g_TradeDone = true;
         Print("Posición cerrada. Día completado (OnlyOnePerDay=ON).");
      }
      else
      {
         Print("Posición cerrada. Re-colocando órdenes...");
         g_OppCancelled = false;
         g_BEApplied    = false;
         g_TicketBuy    = 0;
         g_TicketSell   = 0;
         PlacePendingOrders();
      }
      return;
   }

   bool buyPending  = (g_TicketBuy  > 0 && IsOrderPending(g_TicketBuy));
   bool sellPending = (g_TicketSell > 0 && IsOrderPending(g_TicketSell));
   if(!buyPending && !sellPending)
   {
      g_TradeDone = true;
      Print("Órdenes expiradas sin activación. Día terminado.");
   }
}

//====================================================================
//  ApplyBreakeven
//====================================================================
void ApplyBreakeven(const ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;

   ENUM_POSITION_TYPE posType    = (ENUM_POSITION_TYPE)
                                    PositionGetInteger(POSITION_TYPE);
   double             openPrice  = PositionGetDouble(POSITION_PRICE_OPEN);
   double             currentSL  = PositionGetDouble(POSITION_SL);
   double             currentTP  = PositionGetDouble(POSITION_TP);
   double             beDistance = InpBE_Pips * g_PipSize;
   double             bid        = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double             ask        = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double             newSL      = 0.0;
   bool               doModify   = false;

   if(posType == POSITION_TYPE_BUY)
   {
      if(bid >= openPrice + beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(newSL > currentSL) doModify = true;
      }
   }
   else
   {
      if(ask <= openPrice - beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(currentSL == 0.0 || newSL < currentSL) doModify = true;
      }
   }

   if(doModify)
   {
      if(g_Trade.PositionModify(ticket, newSL, currentTP))
      {
         g_BEApplied = true;
         PrintFormat("BE aplicado | #%d  Nuevo SL=%.5f",
                     (int)ticket, newSL);
      }
      else
         PrintFormat("Error BE: %s (%d)",
                     g_Trade.ResultRetcodeDescription(),
                     g_Trade.ResultRetcode());
   }
}

//====================================================================
//  CalculateLotSize
//====================================================================
double CalculateLotSize()
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk
                     ? (balance * InpRiskPercent / 100.0)
                     : InpRiskUSD;

   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickValue <= 0.0)
   {
      PrintFormat("CalculateLotSize: tick info inválida (tv=%.5f ts=%.5f)",
                  tickValue, tickSize);
      return 0.0;
   }

   double valuePerPip = tickValue * (g_PipSize / tickSize);
   if(valuePerPip <= 0.0) return 0.0;

   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   PrintFormat("Lotaje: %.2f  (Riesgo=$%.2f | $/pip=%.4f | Balance=$%.2f)",
               lots, riskAmount, valuePerPip, balance);
   return lots;
}

//====================================================================
//  Utilidades
//====================================================================
ulong FindOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      ulong t = PositionGetTicket(i);
      if(PositionGetString(POSITION_SYMBOL)  == _Symbol &&
         PositionGetInteger(POSITION_MAGIC)  == (long)InpMagicNumber)
         return t;
   }
   return 0;
}

bool IsOrderPending(const ulong ticket)
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
      if(OrderGetTicket(i) == ticket) return true;
   return false;
}

void CancelAllPendingOrders()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      ulong t = OrderGetTicket(i);
      if(OrderGetInteger(ORDER_MAGIC)  == (long)InpMagicNumber &&
         OrderGetString(ORDER_SYMBOL)  == _Symbol)
      {
         if(g_Trade.OrderDelete(t))
            Print("Orden cancelada: #", (string)t);
         else
            PrintFormat("Error cancelando #%d: %s (%d)",
                        (int)t,
                        g_Trade.ResultRetcodeDescription(),
                        g_Trade.ResultRetcode());
      }
   }
   g_TicketBuy  = 0;
   g_TicketSell = 0;
}

bool IsDayAllowed(const int dow)
{
   switch(dow)
   {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
   }
   return false;
}

ENUM_ORDER_TYPE_FILLING DetectFillingType()
{
   uint filling = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((filling & SYMBOL_FILLING_FOK) != 0) return ORDER_FILLING_FOK;
   if((filling & SYMBOL_FILLING_IOC) != 0) return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
}

string GetStatusStr()
{
   if(g_TradeDone)    return "COMPLETADO";
   if(g_OppCancelled) return "EN POSICIÓN";
   if(g_OrdersPlaced) return "ESPERANDO RUPTURA";
   if(g_RangeBuilt)   return "RANGO DEFINIDO";
   return "DEFINIENDO RANGO";
}

void UpdatePanel(const string status)
{
   string arrow = "↔ NEUTRAL";
   if(g_SPS_Signal == SPS_BULLISH) arrow = "↑ ALCISTA";
   if(g_SPS_Signal == SPS_BEARISH) arrow = "↓ BAJISTA";

   string div = "─────────────────────────────\n";
   string txt =
      "  ORB BREAKOUT EA  v2.00\n"                                         + div +
      "  Símbolo : " + _Symbol + "   TF: M5\n"                            +
      "  Sesión  : " + TimeToString(g_RangeStartTime, TIME_MINUTES) +
      " → " + TimeToString(g_RangeEndTime, TIME_MINUTES) + "\n"           +
      "  H Rango : " + DoubleToString(g_RangeHigh, _Digits) + "\n"        +
      "  L Rango : " + DoubleToString(g_RangeLow,  _Digits) + "\n"        + div +
      "  Estado  : " + status + "\n"                                       +
      "  SPS     : " + arrow  + "\n"                                       +
      "  Score   : " + DoubleToString(g_SPS_Value, 3) +
      "  (±" + DoubleToString(InpSPS_Threshold, 2) + ")\n"                +
      "  BUY  #  : " + (string)g_TicketBuy  + "\n"                        +
      "  SELL #  : " + (string)g_TicketSell + "\n"                        + div;
   Comment(txt);
}
