const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, TabStopType, TabStopPosition
} = require('docx');
const fs = require('fs');

// ── Helpers ────────────────────────────────────────────────────────

const GRAY_DARK  = "2F3136";
const GRAY_MED   = "4A5568";
const BLUE       = "1A56DB";
const BLUE_LIGHT = "EBF4FF";
const GREEN      = "276749";
const GREEN_LIGHT= "F0FFF4";
const RED        = "9B1C1C";
const RED_LIGHT  = "FFF5F5";
const YELLOW_L   = "FFFDE7";
const BORDER_CLR = "CBD5E0";

const border = { style: BorderStyle.SINGLE, size: 1, color: BORDER_CLR };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function h1(text, color = GRAY_DARK) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 300, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: BLUE, space: 4 } },
    children: [new TextRun({ text, bold: true, size: 30, color, font: "Arial" })]
  });
}

function h2(text, color = GRAY_MED) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 220, after: 80 },
    children: [new TextRun({ text, bold: true, size: 24, color, font: "Arial" })]
  });
}

function h3(text) {
  return new Paragraph({
    spacing: { before: 160, after: 60 },
    children: [new TextRun({ text, bold: true, size: 22, color: GRAY_DARK, font: "Arial" })]
  });
}

function p(text, opts = {}) {
  return new Paragraph({
    spacing: { before: 40, after: 80 },
    children: [new TextRun({
      text,
      size: opts.size || 20,
      bold: opts.bold || false,
      color: opts.color || "333333",
      font: "Arial"
    })]
  });
}

function run(text, opts = {}) {
  return new TextRun({ text, size: opts.size || 20, bold: opts.bold || false,
    color: opts.color || "333333", font: "Arial", ...opts });
}

function bullet(text, color = "333333") {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { before: 30, after: 30 },
    children: [new TextRun({ text, size: 20, color, font: "Arial" })]
  });
}

function bullet2(text) {
  return new Paragraph({
    numbering: { reference: "bullets2", level: 0 },
    spacing: { before: 20, after: 20 },
    children: [new TextRun({ text, size: 19, color: "555555", font: "Arial" })]
  });
}

function spacer() {
  return new Paragraph({ spacing: { before: 60, after: 60 }, children: [new TextRun("")] });
}

function divider() {
  return new Paragraph({
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: "E2E8F0", space: 2 } },
    spacing: { before: 100, after: 100 },
    children: [new TextRun("")]
  });
}

function badge(text, bg, textColor = "FFFFFF") {
  return new TableCell({
    borders: noBorders,
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: { top: 60, bottom: 60, left: 160, right: 160 },
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, size: 18, color: textColor, font: "Arial" })]
    })]
  });
}

function metricTable(rows, widths) {
  return new Table({
    width: { size: 9200, type: WidthType.DXA },
    columnWidths: widths,
    rows: rows.map(([label, value, color]) =>
      new TableRow({ children: [
        new TableCell({
          borders, width: { size: widths[0], type: WidthType.DXA },
          shading: { fill: "F7FAFC", type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 140, right: 140 },
          children: [new Paragraph({ children: [run(label, { bold: true, size: 19, color: GRAY_MED })] })]
        }),
        new TableCell({
          borders, width: { size: widths[1], type: WidthType.DXA },
          margins: { top: 80, bottom: 80, left: 140, right: 140 },
          children: [new Paragraph({ children: [run(value, { bold: true, size: 19, color: color || GRAY_DARK })] })]
        }),
      ]})
    )
  });
}

function codeBlock(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    shading: { fill: "F1F5F9", type: ShadingType.CLEAR },
    border: { left: { style: BorderStyle.SINGLE, size: 12, color: BLUE, space: 6 } },
    indent: { left: 200 },
    children: [new TextRun({ text, size: 18, font: "Courier New", color: "1E3A5F" })]
