}

function infoBox(title, lines, bg = BLUE_LIGHT, borderColor = BLUE) {
  const cells = lines.map(line => new Paragraph({
    spacing: { before: 30, after: 30 },
    children: [new TextRun({ text: line, size: 19, font: "Arial", color: "2D3748" })]
  }));
  return new Table({
    width: { size: 9200, type: WidthType.DXA },
    columnWidths: [9200],
    rows: [new TableRow({ children: [
      new TableCell({
        borders: {
          top: { style: BorderStyle.SINGLE, size: 4, color: borderColor },
          bottom: { style: BorderStyle.SINGLE, size: 4, color: borderColor },
          left: { style: BorderStyle.SINGLE, size: 16, color: borderColor },
          right: { style: BorderStyle.SINGLE, size: 4, color: borderColor },
        },
        shading: { fill: bg, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 200, right: 200 },
        children: [
          new Paragraph({ spacing: { after: 60 }, children: [
            new TextRun({ text: title, bold: true, size: 20, font: "Arial", color: borderColor })
          ]}),
          ...cells
        ]
      })
    ]})]
  });
}

